// Script Continued Below
(function executeRule(current, previous /*null when async*/) {
	// STRY0089916 
	current.work_notes = current.assigned_to.getLabel() + " " +  gs.getMessage('Tasker - was updated by') + " " + gs.getUserDisplayName() + "\n" +  gs.getMessage('Tasker - Previous') +  " " + current.assigned_to.getLabel() + ": " + previous.assigned_to.getDisplayValue() + "\n" + gs.getMessage('Tasker - New') +  " " + current.assigned_to.getLabel() + ": " + current.assigned_to.getDisplayValue();


	if(!current.getValue('reassignment_approval') && !current.state.changes()){
		//STRY0105793 - Email Notification when Assigned Member Changes and not requested.
		gs.eventQueue("x_153465_discovert.Task_AsignMem_Chg",current,'','');
	}

})(current, previous);
